import React, { useState, useEffect } from "react";
import api from "../services/axios";

function IncidentList() {
  const [incidents, setIncidents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState("all");

  useEffect(() => {
    fetchIncidents();
  }, []);

  const fetchIncidents = async () => {
    try {
      setLoading(true);
      const response = await api.get("/breaches/");
      setIncidents(response.data);
    } catch (error) {
      console.error("Error fetching incidents", error);
    } finally {
      setLoading(false);
    }
  };

  const getStatusBadge = (status) => {
    const statusClass = status === "open" ? "badge-danger" : "badge-success";
    return <span className={`badge ${statusClass}`}>{status}</span>;
  };

  const filteredIncidents = incidents.filter((incident) => {
    if (filter === "all") return true;
    return incident.status === filter;
  });

  const stats = {
    total: incidents.length,
    open: incidents.filter((i) => i.status === "open").length,
    closed: incidents.filter((i) => i.status === "closed").length,
  };

  if (loading) {
    return (
      <div className="page-loading">
        <div className="spinner"></div>
        <p>Loading incidents...</p>
      </div>
    );
  }

  return (
    <div className="incidents-page">
      <div className="page-header">
        <h1>Incident Management</h1>
        <p>Track and manage security incidents</p>
      </div>

      <div className="stats-grid">
        <div className="stat-card">
          <div className="stat-icon">📋</div>
          <div className="stat-info">
            <h3>{stats.total}</h3>
            <p>Total Incidents</p>
          </div>
        </div>
        <div className="stat-card stat-warning">
          <div className="stat-icon">⚠️</div>
          <div className="stat-info">
            <h3>{stats.open}</h3>
            <p>Open</p>
          </div>
        </div>
        <div className="stat-card stat-success">
          <div className="stat-icon">✅</div>
          <div className="stat-info">
            <h3>{stats.closed}</h3>
            <p>Resolved</p>
          </div>
        </div>
      </div>

      <div className="filter-bar">
        <button
          className={`filter-btn ${filter === "all" ? "active" : ""}`}
          onClick={() => setFilter("all")}
        >
          All ({stats.total})
        </button>
        <button
          className={`filter-btn ${filter === "open" ? "active" : ""}`}
          onClick={() => setFilter("open")}
        >
          Open ({stats.open})
        </button>
        <button
          className={`filter-btn ${filter === "closed" ? "active" : ""}`}
          onClick={() => setFilter("closed")}
        >
          Resolved ({stats.closed})
        </button>
      </div>

      <div className="incidents-list">
        {filteredIncidents.length === 0 ? (
          <div className="empty-state">
            <p>No incidents found</p>
          </div>
        ) : (
          filteredIncidents.map((incident) => (
            <div key={incident.id} className="incident-card">
              <div className="incident-header">
                <h3>{incident.name}</h3>
                {getStatusBadge(incident.status)}
              </div>
              <div className="incident-details">
                {incident.description && <p>{incident.description}</p>}
                {incident.date_discovered && (
                  <span className="incident-date">
                    Discovered: {new Date(incident.date_discovered).toLocaleDateString()}
                  </span>
                )}
              </div>
            </div>
          ))
        )}
      </div>

      <style>{`
        .incidents-page {
          min-height: 100vh;
          background: var(--bg-light);
        }
        .page-header {
          background: var(--secondary-color);
          color: white;
          padding: 30px 40px;
        }
        .page-header h1 {
          font-size: 28px;
          margin-bottom: 8px;
        }
        .page-header p {
          opacity: 0.8;
        }
        .stats-grid {
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
          gap: 20px;
          padding: 30px 40px;
        }
        .stat-card {
          background: white;
          padding: 24px;
          border-radius: var(--radius-lg);
          display: flex;
          align-items: center;
          gap: 16px;
          box-shadow: var(--shadow-sm);
        }
        .stat-icon {
          font-size: 32px;
        }
        .stat-info h3 {
          font-size: 24px;
          color: var(--secondary-color);
        }
        .stat-info p {
          font-size: 14px;
          color: var(--text-muted);
        }
        .stat-card.stat-warning .stat-icon { color: var(--warning-color); }
        .stat-card.stat-success .stat-icon { color: var(--success-color); }
        .filter-bar {
          display: flex;
          gap: 10px;
          padding: 0 40px 20px;
        }
        .filter-btn {
          padding: 10px 20px;
          border: 1px solid var(--border-color);
          background: white;
          border-radius: var(--radius-md);
          cursor: pointer;
          font-size: 14px;
          transition: all 0.2s;
        }
        .filter-btn:hover {
          border-color: var(--primary-color);
        }
        .filter-btn.active {
          background: var(--primary-color);
          color: white;
          border-color: var(--primary-color);
        }
        .incidents-list {
          padding: 0 40px 40px;
          display: flex;
          flex-direction: column;
          gap: 15px;
        }
        .incident-card {
          background: white;
          padding: 20px;
          border-radius: var(--radius-lg);
          box-shadow: var(--shadow-sm);
        }
        .incident-header {
          display: flex;
          justify-content: space-between;
          align-items: center;
          margin-bottom: 10px;
        }
        .incident-header h3 {
          font-size: 16px;
          color: var(--secondary-color);
        }
        .badge {
          padding: 4px 12px;
          border-radius: 20px;
          font-size: 12px;
          font-weight: 600;
          text-transform: capitalize;
        }
        .badge-danger {
          background: #fee2e2;
          color: #dc2626;
        }
        .badge-success {
          background: #d1fae5;
          color: #059669;
        }
        .incident-details p {
          color: var(--text-muted);
          font-size: 14px;
          margin-bottom: 8px;
        }
        .incident-date {
          font-size: 12px;
          color: var(--text-muted);
        }
        .page-loading {
          display: flex;
          flex-direction: column;
          align-items: center;
          justify-content: center;
          min-height: 100vh;
          gap: 15px;
        }
        .empty-state {
          text-align: center;
          padding: 40px;
          color: var(--text-muted);
        }
        @media (max-width: 768px) {
          .stats-grid, .filter-bar, .incidents-list {
            padding-left: 20px;
            padding-right: 20px;
          }
        }
      `}</style>
    </div>
  );
}

export default IncidentList;
